var maxFrequencyElements = function(nums) {
    const cnt = new Map();
    for (const v of nums) cnt.set(v, (cnt.get(v) || 0) + 1);
    let m = 0;
    for (const c of cnt.values()) if (c > m) m = c;
    let total = 0;
    for (const c of cnt.values()) if (c === m) total += c;
    return total;
};
